import React from "react";
import { useNavigate } from "react-router-dom";

const InteractionMode = () => {
    const navigate = useNavigate();

    return (
        <div style={{ textAlign: "center", padding: "50px" }}>
            <h1>Choose your mode of interaction</h1>
            <div style={{ display: "flex", justifyContent: "center", gap: "30px", marginTop: "30px" }}>
                {/* Online Mode */}
                <div
                    onClick={() => navigate("/online")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    <video
                        src="/videos/online-mode.mp4"
                        autoPlay
                        loop
                        muted
                        style={{
                            width: "100%",
                            height: "150px",
                            objectFit: "cover",
                            borderRadius: "8px",
                        }}
                    />
                    <p style={{ marginTop: "10px" }}>Online Mode</p>
                </div>

                {/* Offline Mode */}
                <div
                    onClick={() => navigate("/offline")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    <img
                        src="/images/offline-avatar.png"
                        alt="Offline Mode"
                        style={{
                            width: "100%",
                            height: "150px",
                            objectFit: "cover",
                            borderRadius: "8px",
                        }}
                    />
                    <p style={{ marginTop: "10px" }}>Offline Mode</p>
                </div>
            </div>
        </div>
    );
};

export default InteractionMode;
